<?php
use Admin_Model_FeedbackState as FeedbackState;
use Admin_Model_FeedbackFile as FeedbackFile;
use Admin_Model_FeedbackReadLastState as FeedbackReadLastState;
use user\logic\UserAdminSession;
use common\logic\Email\EmailFactory;

/**
 * Admin_Model_Feedback
 * 
 * This class has been auto-generated by the Doctrine ORM Framework
 * 
 * @package    ##PACKAGE##
 * @subpackage ##SUBPACKAGE##
 * @author     ##NAME## <##EMAIL##>
 * @version    SVN: $Id: Builder.php 7490 2010-03-29 19:53:27Z jwage $
 */
class Admin_Model_Feedback extends Admin_Model_Base_Feedback
{
    const PRIORITY_LOW = 'low';
    const PRIORITY_MEDIUM = 'medium';
    const PRIORITY_HIGH = 'high';

    public function save(Doctrine_Connection $conn = null) {
        $isNew = $this->ID == null;

        if (array_key_exists('Content', $this->getModified()))
            $this->Content = $this->prepareContent();

        if ($isNew) {
            $this->DateTime = date('Y-m-d H:i:s');

            if ( !$this->CreatorUser_ID )
                $this->CreatorUser_ID = UserAdminSession::getCurrentUserID();

            if ( !$this->Eshop_ID )
                $this->Eshop_ID = Common_Model_Eshop::getFirstEshop()->ID;

            $this->tmpState = FeedbackState::STATE_NEW;
            $this->Hash = generateRandomString(32);

            parent::save($conn);

            $this->updateFeedbackNumber();

            EmailFactory::sendFeedbackEmail($this, 'NF');
        }

        parent::save($conn);
    }

    public function delete(Doctrine_Connection $conn = null): bool {
        /** @var FeedbackFile $feedbackFile */
        foreach ($this->feedbackFiles as $feedbackFile) {
            $feedbackFile->delete();
        }

        /** @var FeedbackState $feedbackState */
        foreach ($this->feedbackStates as $feedbackState) {
            $feedbackState->delete();
        }

        /** @var FeedbackReadLastState $feedbackState */
        foreach ($this->feedbackReadLastStates as $feedbackState) {
            $feedbackState->delete();
        }

        return parent::delete($conn);
    }

    public function preUpdate($event)
    {
        parent::preUpdate($event);

        if (array_key_exists('SolverUser_ID', $this->getModified()))
            EmailFactory::sendFeedbackEmail($this, 'RF');

    }

    /**
     * @return void
     */
    private function updateFeedbackNumber() {
        $feedbackNumber = date('Ym') . '0000';
        $feedbackNumber = (int) $feedbackNumber + $this->ID;
        $this->FeedbackNumber = 'FB' . $feedbackNumber;
    }

    public static function getPriorities(): array {
        return [
            self::PRIORITY_LOW => translate('Nízká priorita'),
            self::PRIORITY_MEDIUM => translate('Střední priorita'),
            self::PRIORITY_HIGH => translate('Vysoká priorita'),
        ];
    }

    /**
     * @param FeedbackState $state
     * @throws Exception
     */
    public function updateFeedbackState(FeedbackState $state) {
        $this->tmpState = $state->State;

        switch ($state->State) {
            case FeedbackState::STATE_SOLVED:
                $this->DateSolved = date('Y-m-d');
                break;
        }

        $this->save();
    }

    public static function getFeedbackByID($ID): ?self {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Feedback object');
        $query->where('object.ID = ?');

        $feedback = $query->fetchOne([$ID]);

        if ( !$feedback )
            return null;

        return $feedback;
    }


    public static function getFeedbackNumberByID($ID): ?string {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Feedback object');
        $query->where('object.ID = ?');

        $feedback = $query->fetchOne([$ID]);

        if ( !$feedback )
            return null;

        return $feedback->FeedbackNumber;
    }

    public static function getFeedbackByHash($hash): ?self {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Feedback object');
        $query->where('object.Hash = ?');

        $feedback = $query->fetchOne([$hash]);

        if ( !$feedback )
            return null;

        return $feedback;
    }

    /**
     * @return string
     */
    private function prepareContent() : string {
        $content = $this->Content;

        preg_match_all('/<img[^>]+>/i', $content, $images);
        foreach ( $images[0] as $image ) {
            preg_match_all('/src="([^"]+)"/', $image, $imageSrc);
            $fileName = 'files/feedback/' . uniqid($this->FeedbackNumber . '_') . '.jpg';

            $imageSrc = $imageSrc[0][0];
            if (base64_to_jpeg($imageSrc, $fileName))
                $content = str_replace($imageSrc, 'src="' .  Common_Model_Eshop::getFirstEshop()->URL . '/' . $fileName . '"', $content);
        }

        return html_entity_decode($content, ENT_HTML5 | ENT_NOQUOTES);
    }

    /**
     * @param string $header
     * @param string $content
     * @param bool $errorReporting
     * @param string $priority
     * @param string $dateExpectedSolving
     * @param int|null $solverUserID
     * @param int|null $eshopID
     * @param string|null $dateStartSolving
     * @param string|null $state
     *
     * @return self
     * @throws Exception
     */
    public static function createFeedback(string $header, string $content, bool $errorReporting, string $priority, string $dateExpectedSolving, ?int $solverUserID = null, ?int $eshopID = null, ?string $dateStartSolving = null, ?string $state = null): Admin_Model_Feedback {
        $feedback = new self();
        $feedback->Header = $header;
        $feedback->Content = $content;
        $feedback->Priority = $priority;
        $feedback->ErrorReporting = $errorReporting;
        $feedback->DateExpectedSolving = $dateExpectedSolving;
        $feedback->DateStartSolving = $dateStartSolving;

        if ( $solverUserID )
            $feedback->SolverUser_ID = $solverUserID;

        if ( $eshopID )
            $feedback->Eshop_ID = $eshopID;

        $feedback->save();

        if ($state && $state != FeedbackState::STATE_NEW)
            FeedbackState::createQuickState($feedback->ID, '', $state, false);

        return $feedback;
    }

    /**
     * Nastaví feedback jako přečtený
     * @param int|null $user_ID
     * @return self
     */
    public function addReaded(?int $user_ID = null): self {
        FeedbackReadLastState::addReaded($this->ID, $user_ID);

        return $this;
    }

    /**
     * Vratí iniciály (jména) autora -> řešitele
     * @param bool $asObjecty
     * @return string|object|stdClass|null
     */
    public function getAuthorSolver(bool $asObject = false) {
        $author = $this->CreatorUser_ID?$this->creatorUser->Name:null;
        $solver = $this->SolverUser_ID?$this->solverUser->Name:null;
        $delim = $solver?' -> ':'';
        $hasDelim = !empty($solver);

        if (!$asObject)
            return $author . $delim . $solver;

        if (!$author && !$solver)
            return null;

        return (object) ['author' => $author, 'solver' => $solver, 'delim' => $delim, 'hasDelim' => $hasDelim];
    }

    /**
     * Odstraní zobrazený stav u Feedbacku
     * @param string|int|false|null $user_ID
     * @throws Doctrine_Query_Exception
     */
    public function resetRead($user_ID = null) {
        if ($user_ID === null)
            $user_ID = UserAdminSession::getCurrentUserID();

        FeedbackReadLastState::resetRead($this->ID, $user_ID);
    }
}